"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["3748"],{73377(e,i,a){a.r(i),a.d(i,{default:()=>r});var t=a(74848),o=a(47643),n=JSON.parse('{"id":121,"it":{"title":"Macchina per il test dei kanji giapponesi","prompt":"I want you to act as a Japanese Kanji quiz machine. Each time I ask you for the next question, you are to provide one random Japanese kanji from JLPT N5 kanji list and ask for its meaning. You will generate four options, one correct, three wrong. The options will be labeled from A to D. I will reply to you with one letter, corresponding to one of these labels. You will evaluate my each answer based on your last question and tell me if I chose the right option. If I chose the right label, you will congratulate me. Otherwise you will tell me the right answer. Respond in Italian. Then you will ask me the next question.","description":"Vorrei che interpretaste il ruolo di una macchina per il quiz sui kanji giapponesi. Ogni volta che chieder\xf2 la domanda successiva, fornirete un kanji giapponese a caso dall\'elenco dei kanji del JLPT N5 e chiederete il suo significato. Verranno generate quattro opzioni, una corretta e tre errate. Le opzioni saranno etichettate da A a D. Io risponder\xf2 con una lettera corrispondente a una di queste etichette. Lei valuter\xe0 ogni mia risposta rispetto alla domanda precedente e mi dir\xe0 se ho scelto l\'opzione corretta. Se ho scelto l\'etichetta corretta, mi congratulerete. Altrimenti, mi dir\xe0 qual \xe8 la risposta corretta. Poi farete la domanda successiva.","remark":"Aiuta gli utenti a esercitarsi nel riconoscimento e nella comprensione dei kanji giapponesi."},"tags":["language"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-a-japanese-kanji-quiz-machine","count":308,"related":[{"id":1,"title":"Traduzione o modifica in inglese","remark":"Tradurre altre lingue in inglese o migliorare le frasi in inglese fornite."},{"id":180,"title":"Traduzione bidirezionale in cinese e inglese","remark":"Traduzione inglese-cinese + Stile personalizzabile + Imparare l\'inglese. Contributo di @txmu."},{"id":181,"title":"Traduzione dal cinese all\'inglese - Versione minimalista","remark":"Richiesta di traduttore con risparmio di token per la piattaforma di traduzione basata su API ChatGPT. Contributo di @Qizhen-Yang."}],"metaTitle":"Quiz Kanji: Training N5","metaDescription":"Studi giapponese? Testati con quiz Kanji N5. Identifica significati e ricevi feedback istantaneo. Provalo ora.","faq":[{"q":"Il significato dei kanji pu\xf2 essere sbagliato?","a":"Per kanji di livello N5 (acqua, montagna, persona) l\'accuratezza \xe8 vicina al 100%; al N1 a volte l\'AI propone significati oggi poco usati nel giapponese moderno. Nei dubbi verifica su un dizionario giapponese (Sanseido, K\u014Djien)."},{"q":"Come alzare il livello a N1/N2?","a":"Cambia \xabN5\xbb in \xabN2\xbb o \xabN1\xbb nel prompt. Oppure chiedile \xabscegli 20 domande a caso dalla lista N1 e calcolami la percentuale di risposte corrette\xbb, con \xabsuccessiva\xbb dopo ogni round: manterr\xe0 il ritmo e va bene per l\'autovalutazione."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,t.jsx)(o.A,{prompt:n,currentLanguage:"it"})}}}]);